// 1. Extraer campos del payload Tally.so
// n8n pone el body en $json.body — Tally envía: body.data.fields
const fields = $json.body?.data?.fields ?? [];
const submittedAt = $json.body?.data?.createdAt ?? new Date().toISOString();

// Texto plano (INPUT_TEXT, TEXTAREA)
function getText(keyword) {
  const f = fields.find(f => f.label?.toLowerCase().includes(keyword.toLowerCase()));
  if (!f) return '';
  return String(f.value ?? '');
}

// Dropdown: value es array de IDs → buscar texto en options
function getDropdown(keyword, defaultVal) {
  const f = fields.find(f => f.label?.toLowerCase().includes(keyword.toLowerCase()));
  if (!f || !Array.isArray(f.value) || !f.options) return defaultVal;
  const selectedId = f.value[0];
  const opt = f.options.find(o => o.id === selectedId);
  return opt?.text ?? defaultVal;
}

// Matrix: value es { rowId: [colId] } → devuelve número (texto de columna)
function getMatrix(rowKeyword) {
  const f = fields.find(f => f.type === 'MATRIX');
  if (!f) return 3;
  const row = f.rows?.find(r => r.text?.toLowerCase().includes(rowKeyword.toLowerCase()));
  if (!row) return 3;
  const colIds = f.value?.[row.id];
  if (!colIds?.length) return 3;
  const col = f.columns?.find(c => c.id === colIds[0]);
  return parseFloat(col?.text ?? '3') || 3;
}

return [{
  json: {
    summary:               getText('summarize'),
    pros:                  getText('like most'),
    cons:                  getText('improve'),
    department:            getDropdown('department',    'Engineering & Tech'),
    seniority:             getDropdown('seniority',     'Senior'),
    gender:                getDropdown('gender',        'Prefer not to say'),
    wl_balance:            getMatrix('work-life'),
    culture_values:        getMatrix('culture'),
    diversity_inclusion:   getMatrix('diversity'),
    career_opportunities:  getMatrix('career'),
    compensation_benefits: getMatrix('compensation'),
    senior_management:     getMatrix('senior management'),
    submission_date:       submittedAt.split('T')[0],
    _submitted_at:         submittedAt
  }
}];

// 2. Llamar a FastAPI /predict
const input = $json;

const body = {
  summary:                input.summary,
  pros:                   input.pros,
  cons:                   input.cons,
  department:             input.department,
  seniority:              input.seniority,
  gender:                 input.gender,
  wl_balance:             input.wl_balance,
  culture_values:         input.culture_values,
  diversity_inclusion:    input.diversity_inclusion,
  career_opportunities:   input.career_opportunities,
  compensation_benefits:  input.compensation_benefits,
  senior_management:      input.senior_management,
  submission_date:        input.submission_date
};

const resp = await fetch('http://localhost:8000/predict', {
  method:  'POST',
  headers: { 'Content-Type': 'application/json' },
  body:    JSON.stringify(body)
});

if (!resp.ok) {
  throw new Error(`FastAPI error ${resp.status}: ${await resp.text()}`);
}

const prediction = await resp.json();

// Pasar tanto el input original como la predicción
return [{ json: { ...prediction, _input: input } }];

// 3. Escribir fila en gold.csv
const fs = require('fs');

// Ajusta CSV_PATH a la ruta absoluta de Dashboard/gold.csv en tu máquina
const CSV_PATH = process.env.GOLD_CSV_PATH || './gold.csv';
const COLS = [
  'timestamp', 'submission_date', 'summary', 'pros', 'cons',
  'department', 'seniority', 'gender',
  'wl_balance', 'culture_values', 'diversity_inclusion',
  'career_opportunities', 'compensation_benefits', 'senior_management',
  'predicted_rating', 'satisfaction', 'confidence'
];

const pred  = $json;
const input = pred._input ?? {};

const row = {
  timestamp:              new Date().toISOString(),
  submission_date:        input.submission_date         ?? '',
  summary:                input.summary                 ?? '',
  pros:                   input.pros                    ?? '',
  cons:                   input.cons                    ?? '',
  department:             pred.department               ?? input.department ?? '',
  seniority:              pred.seniority                ?? input.seniority  ?? '',
  gender:                 pred.gender                   ?? input.gender     ?? '',
  wl_balance:             input.wl_balance              ?? '',
  culture_values:         input.culture_values          ?? '',
  diversity_inclusion:    input.diversity_inclusion     ?? '',
  career_opportunities:   input.career_opportunities    ?? '',
  compensation_benefits:  input.compensation_benefits   ?? '',
  senior_management:      input.senior_management       ?? '',
  predicted_rating:       pred.predicted_rating         ?? '',
  satisfaction:           pred.satisfaction             ?? '',
  confidence:             pred.confidence               ?? ''
};

function escapeCSV(val) {
  const s = String(val ?? '');
  return (s.includes(',') || s.includes('"') || s.includes('\n'))
    ? '"' + s.replace(/"/g, '""') + '"'
    : s;
}

// Crear fichero con cabecera si no existe
if (!fs.existsSync(CSV_PATH)) {
  fs.writeFileSync(CSV_PATH, COLS.join(',') + '\n', 'utf8');
}

fs.appendFileSync(CSV_PATH, COLS.map(c => escapeCSV(row[c])).join(',') + '\n', 'utf8');

return [{ json: { status: 'ok', satisfaction: row.satisfaction, predicted_rating: row.predicted_rating } }];
